module dram_cell(  
    input clk,  
    input wr_en,  
    input [15:0] data_in,  
    output reg [15:0] data_out  
);  
    reg [15:0] obf_memory;  

    always @(posedge clk) begin  
        if (wr_en) begin  
            obf_memory <= data_in;  
        end  
        data_out <= obf_memory;  
    end  
endmodule
